            <Link
              to="/tutorial"
              className="hover:text-[#d44a3d] transition-colors py-3 px-2 min-h-[48px] flex items-center"
              onClick={closeMobile}
            >
              [TUTORIAL]
            </Link>
            <Link
              to="/blog"
              className="hover:text-[#d44a3d] transition-colors py-3 px-2 min-h-[48px] flex items-center"
              onClick={closeMobile}
            >
              [BLOG]
            </Link>
            <a
              href="https://github.com/Diogenesoftoronto/keating"
              target="_blank"
              rel="noreferrer"
              className="hover:text-[#d44a3d] transition-colors py-3 px-2 min-h-[48px] flex items-center"
