              className="hover:text-[#d44a3d] transition-colors py-3 px-2 min-h-[48px] flex items-center"
              onClick={closeMobile}
            >
              [GITHUB]
            </a>
            <button
              className="btn-retro px-4 py-4 font-bold text-base mt-2 w-full min-h-[48px]"
              onClick={() => { closeMobile(); navigate("/chat"); }}
            >
              TRY_KEATING
            </button>
          </div>
        </div>
      )}
    </nav>
  );
}

