1	import { getProviders, type Api, type Model } from "@mariozechner/pi-ai";
2	import { localModel, type LocalModel } from "../stores/local-model";
3	import { getSelectableModels } from "../lib/provider-models";
4	
5	const BROWSER_MODEL: Model<Api> = {
6		id: "gemma-4-e4b",
7		name: "Gemma 4 E4B (Browser)",
8		api: "browser" as Api,
9		provider: "browser",
10		baseUrl: "",
11		reasoning: false,
12		input: ["text"],
13		cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
14		contextWindow: 0,
15		maxTokens: 0,
16	};
17	
18	type SelectableModel = {
19		key: string;
20		model: Model<Api>;
21		group: "browser" | "cloud" | "custom";
22	};
23	
24	function modelKey(model: Model<any>): string {
25		return `${model.provider}::${model.api}::${model.id}`;
26	}
27	
28	export class KeatingModelSelector extends HTMLElement {
29		private currentModel: Model<Api> | null = null;
30		private onSelect?: (model: Model<Api>) => void;
31		private selectedKey = modelKey(BROWSER_MODEL);
32		private localModelState: LocalModel | null = null;
33		private webGpuAvailable = false;
34		private searchQuery = "";
35		private unsubscribe?: () => void;
36		private loadingModels = true;
37		private loadError = "";
38		private models: SelectableModel[] = [];
39	
40		static async open(currentModel: Model<Api> | null, onSelect: (model: Model<Api>) => void) {
41			const dialog = new KeatingModelSelector();
42			dialog.currentModel = currentModel;
43			dialog.onSelect = onSelect;
44			dialog.selectedKey = currentModel ? modelKey(currentModel) : modelKey(BROWSER_MODEL);
45			document.body.appendChild(dialog);
46		}
47	
48		constructor() {
49			super();
50			this.attachShadow({ mode: "open" });
51		}
52	
53		async connectedCallback() {
54			this.webGpuAvailable = await this.checkWebGpu();
55			this.unsubscribe = localModel.subscribe((state) => {
56				this.localModelState = state;
57				this.render();
58			});
59			await this.loadModels();
60			this.render();
61		}
62	
63		disconnectedCallback() {
64			this.unsubscribe?.();
65		}
66	
67		private async checkWebGpu(): Promise<boolean> {
68			if (!navigator.gpu) return false;
69			try {
70				return (await navigator.gpu.requestAdapter()) !== null;
71			} catch {
72				return false;
73			}
74		}
75	
76		private async loadModels() {
77			this.loadingModels = true;
78			this.loadError = "";
79			this.render();
80	
81			try {
82				const models = await getSelectableModels();
83				const knownProviders = new Set<string>(getProviders());
84				const selectable: SelectableModel[] = models.map((model) => ({
85					key: modelKey(model),
86					model,
87					group:
88						model.provider === "browser"
89							? "browser"
90							: knownProviders.has(model.provider)
91								? "cloud"
92								: "custom",
93				}));
94	
95				if (this.webGpuAvailable) {
96					selectable.unshift({ key: modelKey(BROWSER_MODEL), model: BROWSER_MODEL, group: "browser" });
97				}
98	
99				const deduped = new Map<string, SelectableModel>();
100				for (const model of selectable) {
101					deduped.set(model.key, model);
102				}
103	
104				this.models = Array.from(deduped.values());
105				if (!this.models.some((entry) => entry.key === this.selectedKey) && this.models[0]) {
106					this.selectedKey = this.models[0].key;
107				}
108			} catch (error) {
109				this.loadError = error instanceof Error ? error.message : String(error);
110				this.models = this.webGpuAvailable
111					? [{ key: modelKey(BROWSER_MODEL), model: BROWSER_MODEL, group: "browser" }]
112					: [];
113			} finally {
114				this.loadingModels = false;
115			}
116		}
117	
118		private getFilteredModels(): SelectableModel[] {
119			const query = this.searchQuery.trim().toLowerCase();
120			if (!query) return this.models;
121	
122			return this.models.filter(({ model }) => {
123				const haystack = `${model.name} ${model.id} ${model.provider}`.toLowerCase();
124				return haystack.includes(query);
125			});
126		}
127	
128		private renderGroup(title: string, group: SelectableModel["group"], models: SelectableModel[]): string {
129			if (models.length === 0) return "";
130	
131			return `
132	      <div class="category">${title}</div>
133	      ${models.map((entry) => this.renderModelOption(entry)).join("")}
134	    `;
135		}
136	
137		private renderModelOption(entry: SelectableModel): string {
138			const { model, key } = entry;
139			const isSelected = this.selectedKey === key;
140			const isBrowser = model.provider === "browser";
141			const statusHtml = this.renderStatus(model);
142			const disabled = isBrowser && !this.webGpuAvailable;
143			const badges = [
144				isBrowser ? '<span class="badge badge-browser">WebGPU</span>' : "",
145				entry.group === "cloud" ? '<span class="badge badge-key">Cloud</span>' : "",
146				entry.group === "custom" ? '<span class="badge badge-local">Custom</span>' : "",
147				model.input.includes("image") ? '<span class="badge badge-vision">Vision</span>' : "",
148				model.reasoning ? '<span class="badge badge-thinking">Thinking</span>' : "",
149			]
150				.filter(Boolean)
151				.join("");
152	
153			const providerLabel = isBrowser ? "Runs in this browser" : `Provider: ${model.provider}`;
154			return `
155	      <div class="model-option ${isSelected ? "selected" : ""} ${disabled ? "disabled" : ""}" data-model-key="${key}">
156	        <input type="radio" name="model" value="${key}" class="model-radio" ${isSelected ? "checked" : ""} ${disabled ? "disabled" : ""}>
157	        <div class="model-info">
158	          <div class="model-name">${model.name}</div>
159	          <div class="model-desc">${providerLabel}</div>
160	          <div class="model-id">${model.id}</div>
161	          <div class="badges">${badges}</div>
162	          ${statusHtml}
163	        </div>
164	      </div>
165	    `;
166		}
167	
168		private renderStatus(model: Model<Api>): string {
169			if (model.provider !== "browser") return "";
170			if (!this.webGpuAvailable) return `<div class="status status-error">WebGPU not available</div>`;
171			if (this.localModelState?.loading) {
172				return `
173	        <div class="status status-loading">Loading browser model... ${this.localModelState.loadingProgress}%</div>
174	        <div class="progress-bar">
175	          <div class="progress-fill" style="width: ${this.localModelState.loadingProgress}%"></div>
176	        </div>
177	      `;
178			}
179			if (this.localModelState?.loaded) return `<div class="status status-loaded">Model ready</div>`;
180			if (this.localModelState?.error) return `<div class="status status-error">${this.localModelState.error}</div>`;
181			return `<div class="status">Loads on demand when selected</div>`;
182		}
183	
184		private bindEvents() {
185			this.shadowRoot?.querySelector("#cancel")?.addEventListener("click", () => this.remove());
186			this.shadowRoot?.querySelector("#search")?.addEventListener("input", (event) => {
187				this.searchQuery = (event.target as HTMLInputElement).value;
188				this.render();
189			});
190			this.shadowRoot?.querySelector("#refresh")?.addEventListener("click", async () => {
191				await this.loadModels();
192				this.render();
193			});
194			this.shadowRoot?.querySelector("#select")?.addEventListener("click", async () => {
195				const selected = this.models.find((entry) => entry.key === this.selectedKey)?.model;
196				if (!selected) return;
197	
198				if (selected.provider === "browser" && !this.localModelState?.loaded) {
199					await localModel.load();
200					if (!localModel.getState().loaded) {
201						this.render();
202						return;
203					}
204				}
205	
206				this.onSelect?.(selected);
207				this.remove();
208			});
209	
210			this.shadowRoot?.querySelectorAll(".model-option").forEach((element) => {
211				element.addEventListener("click", () => {
212					if (element.classList.contains("disabled")) return;
213					this.selectedKey = (element as HTMLElement).dataset.modelKey || this.selectedKey;
214					this.render();
215				});
